from typing import Dict, Union

OPCODE_R    = 0b0110011
OPCODE_I    = 0b0010011
OPCODE_LOAD = 0b0000011
OPCODE_STORE= 0b0100011
OPCODE_BEQ  = 0b1100011
OPCODE_JAL  = 0b1101111
OPCODE_LUI  = 0b0110111

OPCODE_NAMES = {
    OPCODE_R: 'R-type', OPCODE_I: 'I-arith', OPCODE_LOAD: 'Load',
    OPCODE_STORE: 'Store', OPCODE_BEQ: 'Branch', OPCODE_JAL: 'JAL',
    OPCODE_LUI: 'LUI',
}


def generate_main_control(opcode: int) -> Dict[str, Union[bool, int]]:
    ctrl = {
        'reg_write': False, 'alu_src': False, 'mem_read': False,
        'mem_write': False, 'mem_to_reg': False, 'branch': False,
        'jump': False, 'alu_op': 0,
    }

    if opcode == OPCODE_R:
        ctrl['reg_write'] = True
        ctrl['alu_op'] = 2
    elif opcode == OPCODE_I:
        ctrl['reg_write'] = True
        ctrl['alu_src'] = True
        ctrl['alu_op'] = 2
    elif opcode == OPCODE_LOAD:
        ctrl['reg_write'] = True
        ctrl['alu_src'] = True
        ctrl['mem_read'] = True
        ctrl['mem_to_reg'] = True
        ctrl['alu_op'] = 0
    elif opcode == OPCODE_STORE:
        ctrl['alu_src'] = True
        ctrl['mem_write'] = True
        ctrl['alu_op'] = 0
    elif opcode == OPCODE_BEQ:
        ctrl['branch'] = True
        ctrl['alu_op'] = 1
    elif opcode == OPCODE_JAL:
        ctrl['reg_write'] = True
        ctrl['jump'] = True
    elif opcode == OPCODE_LUI:
        ctrl['reg_write'] = True
        ctrl['alu_src'] = True
        ctrl['alu_op'] = 3

    return ctrl


def generate_alu_control(
    alu_op: int, funct3: int, funct7_bit5: int
) -> Dict[str, Union[int, str]]:
    if alu_op == 0:
        return {'alu_control': 0b0010, 'operation': 'ADD'}
    elif alu_op == 1:
        return {'alu_control': 0b0110, 'operation': 'SUB'}
    elif alu_op == 3:
        return {'alu_control': 0b0010, 'operation': 'PASS'}
    elif alu_op == 2:
        alu_map = {
            (0b000, 0): {'alu_control': 0b0010, 'operation': 'ADD'},
            (0b000, 1): {'alu_control': 0b0110, 'operation': 'SUB'},
            (0b001, 0): {'alu_control': 0b0011, 'operation': 'SLL'},
            (0b010, 0): {'alu_control': 0b0111, 'operation': 'SLT'},
            (0b100, 0): {'alu_control': 0b1000, 'operation': 'XOR'},
            (0b101, 0): {'alu_control': 0b0101, 'operation': 'SRL'},
            (0b101, 1): {'alu_control': 0b1101, 'operation': 'SRA'},
            (0b110, 0): {'alu_control': 0b0001, 'operation': 'OR'},
            (0b111, 0): {'alu_control': 0b0000, 'operation': 'AND'},
        }
        key = (funct3, funct7_bit5)
        if key in alu_map:
            return alu_map[key]
        # For I-type, funct7_bit5 may not matter for some operations
        key_default = (funct3, 0)
        if key_default in alu_map:
            return alu_map[key_default]
        return {'alu_control': 0b0010, 'operation': 'ADD'}
    return {'alu_control': 0b0010, 'operation': 'ADD'}


def trace_instruction(instruction: int) -> Dict:
    opcode = instruction & 0x7F
    funct3 = (instruction >> 12) & 0x7
    funct7 = (instruction >> 25) & 0x7F
    funct7_bit5 = (funct7 >> 5) & 0x1

    main_ctrl = generate_main_control(opcode)
    alu_ctrl = generate_alu_control(main_ctrl['alu_op'], funct3, funct7_bit5)

    return {
        'opcode_name': OPCODE_NAMES.get(opcode, 'Unknown'),
        'main_control': main_ctrl,
        'alu_control': alu_ctrl['alu_control'],
        'alu_operation': alu_ctrl['operation'],
    }

