from typing import List, Dict, Tuple


class MultiCycleFSM:
    """Finite state machine controller for multi-cycle RISC-V."""

    STATES = ['FETCH', 'DECODE', 'EXEC_R', 'EXEC_ADDR',
              'MEM_READ', 'MEM_WRITE', 'BRANCH', 'WB_ALU', 'WB_MEM']

    OPCODE_R     = 0b0110011
    OPCODE_I     = 0b0010011
    OPCODE_LOAD  = 0b0000011
    OPCODE_STORE = 0b0100011
    OPCODE_BEQ   = 0b1100011
    OPCODE_JAL   = 0b1101111

    def __init__(self):
        self.state: str = 'FETCH'

    def get_state(self) -> str:
        return self.state

    def get_signals(self) -> Dict[str, int]:
        s: Dict[str, int] = {
            'alu_src_a': 0, 'alu_src_b': 0, 'alu_op': 0,
            'mem_read': 0, 'mem_write': 0, 'i_or_d': 0,
            'ir_write': 0, 'reg_write': 0, 'mem_to_reg': 0,
            'pc_write': 0, 'branch': 0,
        }

        if self.state == 'FETCH':
            s['mem_read'] = 1
            s['i_or_d'] = 0
            s['ir_write'] = 1
            s['alu_src_a'] = 0
            s['alu_src_b'] = 1  # constant 4
            s['alu_op'] = 0     # ADD
            s['pc_write'] = 1
        elif self.state == 'DECODE':
            s['alu_src_a'] = 0  # PC
            s['alu_src_b'] = 2  # immediate
            s['alu_op'] = 0     # ADD (branch target)
        elif self.state == 'EXEC_R':
            s['alu_src_a'] = 1
            s['alu_src_b'] = 0
            s['alu_op'] = 2     # function-determined
        elif self.state == 'EXEC_ADDR':
            s['alu_src_a'] = 1
            s['alu_src_b'] = 2
            s['alu_op'] = 0     # ADD for address
        elif self.state == 'MEM_READ':
            s['mem_read'] = 1
            s['i_or_d'] = 1     # from ALUOut
        elif self.state == 'MEM_WRITE':
            s['mem_write'] = 1
            s['i_or_d'] = 1
        elif self.state == 'BRANCH':
            s['alu_src_a'] = 1
            s['alu_src_b'] = 0
            s['alu_op'] = 1     # SUB
            s['branch'] = 1
        elif self.state == 'WB_ALU':
            s['reg_write'] = 1
            s['mem_to_reg'] = 0
        elif self.state == 'WB_MEM':
            s['reg_write'] = 1
            s['mem_to_reg'] = 1

        return s

    def advance(self, opcode: int) -> str:
        transitions = {
            'FETCH': 'DECODE',
            'EXEC_R': 'WB_ALU',
            'EXEC_ADDR': lambda op: 'MEM_READ' if op == self.OPCODE_LOAD else 'MEM_WRITE',
            'MEM_READ': 'WB_MEM',
            'MEM_WRITE': 'FETCH',
            'BRANCH': 'FETCH',
            'WB_ALU': 'FETCH',
            'WB_MEM': 'FETCH',
        }

        if self.state == 'DECODE':
            if opcode in (self.OPCODE_R, self.OPCODE_I):
                self.state = 'EXEC_R'
            elif opcode in (self.OPCODE_LOAD, self.OPCODE_STORE):
                self.state = 'EXEC_ADDR'
            elif opcode in (self.OPCODE_BEQ, self.OPCODE_JAL):
                self.state = 'BRANCH'
            else:
                self.state = 'EXEC_R'
        elif self.state in transitions:
            nxt = transitions[self.state]
            if callable(nxt):
                self.state = nxt(opcode)
            else:
                self.state = nxt
        else:
            self.state = 'FETCH'

        return self.state

    def execute_instruction(self, opcode: int) -> List[Tuple[str, Dict]]:
        self.state = 'FETCH'
        trace: List[Tuple[str, Dict]] = []
        while True:
            state_name = self.state
            signals = self.get_signals()
            trace.append((state_name, signals))
            self.advance(opcode)
            if self.state == 'FETCH':
                break
        return trace

    def count_cycles(self, opcode: int) -> int:
        return len(self.execute_instruction(opcode))

from typing import Dict


MULTI_CYCLE_COUNTS = {
    'r_type': 4,
    'load': 5,
    'store': 4,
    'branch': 3,
    'jump': 3,
}


class PerformanceComparator:
    """Compare single-cycle vs multi-cycle processor performance."""

    def __init__(self, component_delays: Dict[str, float]):
        self.delays = component_delays

    def single_cycle_clock(self) -> float:
        d = self.delays
        return (d['imem'] + d['reg_read'] + d['mux'] +
                d['alu'] + d['dmem'] + d['mux'] + d['reg_write'])

    def multi_cycle_clock(self) -> float:
        d = self.delays
        mem_step = max(d['imem'], d['dmem'])
        alu_step = d['alu']
        reg_step = d['reg_read'] + d['reg_write'] + d['mux']
        return max(mem_step, alu_step, reg_step)

    def single_cycle_time(self, instruction_count: int) -> float:
        return instruction_count * self.single_cycle_clock()

    def multi_cycle_time(self, instruction_mix: Dict[str, int]) -> float:
        clk = self.multi_cycle_clock()
        total_cycles = 0
        for inst_type, count in instruction_mix.items():
            cycles_per = MULTI_CYCLE_COUNTS.get(inst_type, 4)
            total_cycles += count * cycles_per
        return total_cycles * clk

    def compare(self, instruction_mix: Dict[str, int]) -> Dict:
        total_instructions = sum(instruction_mix.values())

        sc_clk = self.single_cycle_clock()
        sc_time = self.single_cycle_time(total_instructions)

        mc_clk = self.multi_cycle_clock()
        mc_time = self.multi_cycle_time(instruction_mix)

        total_mc_cycles = 0
        for inst_type, count in instruction_mix.items():
            total_mc_cycles += count * MULTI_CYCLE_COUNTS.get(inst_type, 4)
        avg_cpi = total_mc_cycles / total_instructions if total_instructions > 0 else 0

        speedup = sc_time / mc_time if mc_time > 0 else 0

        return {
            'single_cycle': {
                'clock_ps': sc_clk,
                'cpi': 1.0,
                'total_time_ps': sc_time,
            },
            'multi_cycle': {
                'clock_ps': mc_clk,
                'avg_cpi': round(avg_cpi, 3),
                'total_time_ps': mc_time,
            },
            'speedup': round(speedup, 4),
            'total_instructions': total_instructions,
        }
